     4→//! Steeplechase entries are stored in git commit messages, not the Gallops JSON.
     5→//!
     6→//! New commit format: `jjb:BRAND:IDENTITY[:ACTION]: message`
     7→//! - IDENTITY: ₢CORONET for pace-level, ₣FIREMARK for heat-level
     8→//! - ACTION: Single letter code (optional for standard notch)
     9→
    10→use serde::Serialize;
    11→use std::process::Command;
    12→
    13→use crate::jjrf_favor::{Firemark, FIREMARK_PREFIX, CORONET_PREFIX};
    14→
    15→/// Arguments for jjx_rein command
    16→#[derive(Debug)]
    17→pub struct ReinArgs {
    18→    /// Target Heat identity (Firemark, with or without prefix)
    19→    pub firemark: String,
    20→
    21→    /// Repository brand identifier (from arcanum installation)
    22→    pub brand: String,
    23→
    24→    /// Maximum entries to return
    25→    pub limit: usize,
    26→}
    27→
    28→/// Steeplechase entry - parsed from git commit message
    29→#[derive(Debug, Clone, Serialize)]
    30→pub struct SteeplechaseEntry {
    31→    /// Timestamp in "YYYY-MM-DD HH:MM" format
    32→    pub timestamp: String,
    33→
    34→    /// Coronet for pace-level entries, None for heat-level
    35→    #[serde(skip_serializing_if = "Option::is_none")]
    36→    pub coronet: Option<String>,
    37→
    38→    /// Action code (single letter), None for standard notch commits
    39→    #[serde(skip_serializing_if = "Option::is_none")]
    40→    pub action: Option<String>,
    41→
    42→    /// Commit message or marker description
    43→    pub subject: String,
    44→}
    45→
    46→/// Parse timestamp from git %ai format to "YYYY-MM-DD HH:MM"
    47→/// Input format: "2024-01-15 14:30:00 -0800"
    48→fn parse_timestamp(git_timestamp: &str) -> String {
    49→    let trimmed = git_timestamp.trim();
    50→    if trimmed.len() >= 16 {
    51→        trimmed[..16].to_string()
    52→    } else {
    53→        trimmed.to_string()
    54→    }
    55→}
    56→
    57→/// Parse a new-format commit: jjb:BRAND:IDENTITY[:ACTION]: message
    58→/// Returns (coronet_option, action_option, message) if successful
    59→fn parse_new_format(subject: &str, brand: &str, firemark_raw: &str) -> Option<SteeplechaseEntry> {
    60→    // Expected format: jjb:BRAND:IDENTITY[:ACTION]: message
    61→    let prefix = format!("jjb:{}:", brand);
    62→    if !subject.starts_with(&prefix) {
    63→        return None;
    64→    }
    65→
    66→    let after_brand = &subject[prefix.len()..];
    67→
    68→    // Parse identity (₢CORONET or ₣FIREMARK)
    69→    let (identity, rest) = if after_brand.starts_with(CORONET_PREFIX) {
    70→        // Coronet: ₢XXXXX (1 prefix char + 5 base64 chars = 6 chars total in UTF-8)
    71→        let coronet_end = CORONET_PREFIX.len_utf8() + 5;
    72→        if after_brand.len() < coronet_end {
    73→            return None;
    74→        }
    75→        let coronet = &after_brand[..coronet_end];
    76→        // Verify this coronet belongs to our heat (first 2 chars of base64 match firemark)
    77→        let coronet_heat = &after_brand[CORONET_PREFIX.len_utf8()..CORONET_PREFIX.len_utf8() + 2];
    78→        if coronet_heat != firemark_raw {
    79→            return None;
    80→        }
    81→        (Some(coronet.to_string()), &after_brand[coronet_end..])
    82→    } else if after_brand.starts_with(FIREMARK_PREFIX) {
    83→        // Firemark: ₣XX (1 prefix char + 2 base64 chars)
    84→        let firemark_end = FIREMARK_PREFIX.len_utf8() + 2;
    85→        if after_brand.len() < firemark_end {
    86→            return None;
    87→        }
    88→        // Verify this is our firemark
    89→        let fm = &after_brand[FIREMARK_PREFIX.len_utf8()..firemark_end];
    90→        if fm != firemark_raw {
    91→            return None;
    92→        }
    93→        (None, &after_brand[firemark_end..])
    94→    } else {
    95→        return None;
    96→    };
    97→
    98→    // Now parse: [:ACTION]: message
    99→    // rest should start with either ": " (no action) or ":X: " (with action)
   100→    if !rest.starts_with(':') {
   101→        return None;
   102→    }
   103→
   104→    let after_colon = &rest[1..];
   105→
   106→    let (action, message) = if after_colon.starts_with(' ') {
   107→        // No action code, just ": message"
   108→        (None, after_colon[1..].to_string())
   109→    } else {
   110→        // Has action code: "X: message"
   111→        // Find the next colon
   112→        if let Some(colon_pos) = after_colon.find(':') {
   113→            let action_code = &after_colon[..colon_pos];
   114→            let msg = after_colon[colon_pos + 1..].trim_start().to_string();
   115→            (Some(action_code.to_string()), msg)
   116→        } else {
   117→            return None;
   118→        }
   119→    };
   120→
   121→    Some(SteeplechaseEntry {
   122→        timestamp: String::new(), // filled by caller
   123→        coronet: identity,
   124→        action,
   125→        subject: message,
   126→    })
   127→}
   128→
   129→/// Parse a single git log line into a SteeplechaseEntry
   130→/// Line format: "YYYY-MM-DD HH:MM:SS -ZZZZ<TAB>subject"
   131→fn parse_log_line(line: &str, brand: &str, firemark_raw: &str) -> Option<SteeplechaseEntry> {
   132→    let parts: Vec<&str> = line.splitn(2, '\t').collect();
   133→    if parts.len() != 2 {
   134→        return None;
   135→    }
   136→
   137→    let timestamp = parse_timestamp(parts[0]);
   138→    let subject = parts[1];
   139→
   140→    // Try parsing new format
   141→    if let Some(mut entry) = parse_new_format(subject, brand, firemark_raw) {
   142→        entry.timestamp = timestamp;
   143→        return Some(entry);
   144→    }
   145→
   146→    None
   147→}
