   149→/// Get steeplechase entries for a heat (library function)
   150→pub fn get_entries(args: &ReinArgs) -> Result<Vec<SteeplechaseEntry>, String> {
   151→    let firemark = Firemark::parse(&args.firemark)
   152→        .map_err(|e| format!("Invalid firemark: {}", e))?;
   153→
   154→    let firemark_raw = firemark.as_str();
   155→
   156→    // Build the grep pattern for git log
   157→    // Pattern matches both heat-level (₣XX) and pace-level (₢XX...) entries
   158→    // jjb:BRAND:₣XX or jjb:BRAND:₢XX
   159→    let grep_pattern = format!(
   160→        "^jjb:{}:({}{}|{}{})",
   161→        args.brand,
   162→        FIREMARK_PREFIX, firemark_raw,
   163→        CORONET_PREFIX, firemark_raw
   164→    );
   165→
   166→    let output = Command::new("git")
   167→        .args([
   168→            "log",
   169→            "--all",
   170→            "--extended-regexp",
   171→            &format!("--grep={}", grep_pattern),
   172→            "--format=%ai\t%s",
   173→        ])
   174→        .output()
   175→        .map_err(|e| format!("Failed to run git log: {}", e))?;
   176→
   177→    if !output.status.success() {
   178→        let stderr = String::from_utf8_lossy(&output.stderr);
   179→        return Err(format!("git log failed: {}", stderr));
   180→    }
   181→
   182→    let stdout = String::from_utf8_lossy(&output.stdout);
   183→
   184→    let entries: Vec<SteeplechaseEntry> = stdout
   185→        .lines()
   186→        .filter_map(|line| parse_log_line(line, &args.brand, firemark_raw))
   187→        .take(args.limit)
   188→        .collect();
   189→
   190→    Ok(entries)
