    } else if after_brand.starts_with(FIREMARK_PREFIX) {
        // Firemark: ₣XX (1 prefix char + 2 base64 chars)
        let firemark_end = FIREMARK_PREFIX.len_utf8() + 2;
        if after_brand.len() < firemark_end {
            return None;
        }
        // Verify this is our firemark
